section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/agency-content-pillars-niche.json",
  "title": "Agency Content Pillars (Niche) playbook step",
  "type": "object",
  "required": [
    "slug",
    "owner",
    "steps",
    "decision_branches",
    "deviation_log_reference"
  ],
  "properties": {
    "slug": {
      "type": "string",
      "const": "agency-content-pillars-niche"
    },
    "owner": {
      "type": "string",
      "minLength": 1
    },
    "steps": {
      "type": "array",
      "minItems": 4,
      "items": {
        "type": "object",
        "required": [
          "id",
          "input",
          "owner",
          "exit_criterion",
          "output_location"
        ],
        "properties": {
          "id": {
            "type": "string"
          },
          "input": {
            "type": "string"
          },
          "owner": {
            "type": "string"
          },
          "exit_criterion": {
            "type": "string",
            "minLength": 10
          },
          "output_location": {
            "type": "string"
          }
        },
        "additionalProperties": false
      }
    },
    "decision_branches": {
      "type": "array",
      "items": {
        "type": "object",
        "required": [
          "when",
          "then"
        ],
        "properties": {
          "when": {
            "type": "string"
          },
          "then": {
            "type": "string"
          }
        },
        "additionalProperties": false
      }
    },
    "deviation_log_reference": {
      "type": "string",
      "minLength": 1
    }
  },
  "additionalProperties": false
}

example.code:
{
  "slug": "agency-content-pillars-niche",
  "owner": "playbook owner",
  "steps": [
    {
      "id": "s1",
      "input": "brief",
      "owner": "lead",
      "exit_criterion": "brief reviewed + scope confirmed",
      "output_location": "docs/briefs/"
    },
    {
      "id": "s2",
      "input": "data",
      "owner": "analyst",
      "exit_criterion": "dataset >=30 records validated",
      "output_location": "warehouse:tbl"
    },
    {
      "id": "s3",
      "input": "draft",
      "owner": "writer",
      "exit_criterion": "draft passes editorial check",
      "output_location": "docs/drafts/"
    },
    {
      "id": "s4",
      "input": "draft",
      "owner": "lead",
      "exit_criterion": "signed off by named reviewer",
      "output_location": "docs/published/"
    }
  ],
  "decision_branches": [
    {
      "when": "data_records < 30",
      "then": "loop back to s2"
    }
  ],
  "deviation_log_reference": "ops/deviation-log.md#L101"
}
